export const getMarketData = async () => {
    // Daha uzun ve gerçekçi veri seti
    return [
        { symbol: 'ONS/USD', price: '$2,345.50', trend: 'up' },
        { symbol: 'GRAM', price: '₺2,450.00', trend: 'up' },
        { symbol: 'USD/TRY', price: '₺32.65', trend: 'down' },
        { symbol: 'EUR/TRY', price: '₺35.20', trend: 'up' },
        { symbol: 'GBP/TRY', price: '₺41.10', trend: 'up' },
        { symbol: 'BTC/USD', price: '$68,400', trend: 'down' },
        { symbol: 'ETH/USD', price: '$3,850', trend: 'up' },
        { symbol: 'ÇEYREK', price: '₺4,150.00', trend: 'up' },
        { symbol: 'CUMHURİYET', price: '₺16,500.00', trend: 'up' },
    ];
};
